object BucketSort {
    fun sort(arr: IntArray): IntArray {
        if (arr.size <= 1) {
            return arr.copyOf()
        }

        val n = arr.size
        var min = arr[0]
        var max = arr[0]

        for (i in 1 until n) {
            if (arr[i] < min) min = arr[i]
            if (arr[i] > max) max = arr[i]
        }

        if (min == max) {
            return arr.copyOf()
        }

        // Initialize buckets
        val buckets = Array(n) { mutableListOf<Int>() }
        val range = max.toLong() - min

        // Distribute elements into buckets
        for (x in arr) {
            val index = ((x.toLong() - min) * (n - 1) / range).toInt()
            buckets[index].add(x)
        }

        // Sort each bucket and merge
        val result = IntArray(n)
        var k = 0
        for (bucket in buckets) {
            if (bucket.isNotEmpty()) {
                bucket.sort()
                for (x in bucket) {
                    result[k++] = x
                }
            }
        }

        return result
    }
}

/**
 * Bucket Sort implementation.
 * Divides the input into several buckets, each of which is then sorted individually.
 */
pub fn bucket_sort(arr: &[i32]) -> Vec<i32> {
    if arr.len() <= 1 {
        return arr.to_vec();
    }

    let n = arr.len();
    let &min_val = arr.iter().min().unwrap();
    let &max_val = arr.iter().max().unwrap();

    if min_val == max_val {
        return arr.to_vec();
    }

    // Initialize buckets
    let mut buckets: Vec<Vec<i32>> = vec![Vec::new(); n];
    let range = (max_val as i64) - (min_val as i64);

    // Distribute elements into buckets
    for &x in arr {
        let index = (((x as i64) - (min_val as i64)) * ((n - 1) as i64) / range) as usize;
        buckets[index].push(x);
    }

    // Sort each bucket and merge
    let mut result = Vec::with_capacity(n);
    for mut bucket in buckets {
        if !bucket.is_empty() {
            bucket.sort_unstable();
            result.extend(bucket);
        }
    }

    result
}

