import scala.collection.mutable.ListBuffer

/**
 * Bucket Sort implementation.
 * Divides the input into several buckets, each of which is then sorted individually.
 */
object BucketSort {
  def sort(arr: Array[Int]): Array[Int] = {
    if (arr.length <= 1) {
      return arr.clone()
    }

    val n = arr.length
    val minVal = arr.min
    val maxVal = arr.max

    if (minVal == maxVal) {
      return arr.clone()
    }

    // Initialize buckets
    val buckets = Array.fill(n)(ListBuffer.empty[Int])
    val range = maxVal.toLong - minVal

    // Distribute elements into buckets
    for (x <- arr) {
      val index = ((x.toLong - minVal) * (n - 1) / range).toInt
      buckets(index) += x
    }

    // Sort each bucket and merge
    val result = new Array[Int](n)
    var k = 0
    for (bucket <- buckets) {
      if (bucket.nonEmpty) {
        val sortedBucket = bucket.sorted
        for (x <- sortedBucket) {
          result(k) = x
          k += 1
        }
      }
    }

    result
  }
}

/**
 * Bucket Sort implementation.
 * Divides the input into several buckets, each of which is then sorted individually.
 */
public class BucketSort {
    public static func sort(_ arr: [Int]) -> [Int] {
        guard arr.count > 1 else {
            return arr
        }

        let n = arr.count
        guard let minVal = arr.min(), let maxVal = arr.max() else {
            return arr
        }

        if minVal == maxVal {
            return arr
        }

        // Initialize buckets
        var buckets: [[Int]] = Array(repeating: [], count: n)
        let range = Double(maxVal - minVal)

        // Distribute elements into buckets
        for x in arr {
            let index = Int(Double(x - minVal) * Double(n - 1) / range)
            buckets[index].append(x)
        }

        // Sort each bucket and merge
        var result: [Int] = []
        result.reserveCapacity(n)
        for i in 0..<n {
            if !buckets[i].isEmpty {
                let sortedBucket = buckets[i].sorted()
                result.append(contentsOf: sortedBucket)
            }
        }

        return result
    }
}

/**
 * Bucket Sort implementation.
 * Divides the input into several buckets, each of which is then sorted individually.
 * @param arr the input array
 * @returns a sorted copy of the array
 */
export function bucketSort(arr: number[]): number[] {
    const n = arr.length;
    if (n <= 1) {
        return [...arr];
    }

    let min = arr[0];
    let max = arr[0];
    for (let i = 1; i < n; i++) {
        if (arr[i] < min) min = arr[i];
        if (arr[i] > max) max = arr[i];
    }

    if (min === max) {
        return [...arr];
    }

    // Initialize buckets
    const buckets: number[][] = Array.from({ length: n }, () => []);
    const range = max - min;

    // Distribute elements into buckets
    for (const x of arr) {
        const index = Math.floor(((x - min) * (n - 1)) / range);
        buckets[index].push(x);
    }

    // Sort each bucket and merge
    const result: number[] = [];
    for (const bucket of buckets) {
        if (bucket.length > 0) {
            // Using built-in sort for simplicity
            bucket.sort((a, b) => a - b);
            result.push(...bucket);
        }
    }

    return result;
}
